package com.example.mfa.security;

import java.security.SecureRandom;
import java.util.Base64;
import java.util.List;
import java.util.stream.Collectors;
import java.util.stream.IntStream;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.stereotype.Component;

@Component
public class BackupCodeService {
    private final SecureRandom secureRandom = new SecureRandom();
    private final BCryptPasswordEncoder passwordEncoder = new BCryptPasswordEncoder();

    public List<String> generatePlainBackupCodes(int count) {
        return IntStream.range(0, count)
                .mapToObj(i -> generateCode())
                .collect(Collectors.toList());
    }

    public List<String> hashBackupCodes(List<String> codes) {
        return codes.stream()
                .map(passwordEncoder::encode)
                .collect(Collectors.toList());
    }

    public boolean matches(String rawCode, String hash) {
        return passwordEncoder.matches(rawCode, hash);
    }

    public String generateCode() {
        byte[] bytes = new byte[10];
        secureRandom.nextBytes(bytes);
        String code = Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
        return formatCode(code);
    }

    private String formatCode(String code) {
        String normalized = code.replace("-", "").replace("_", "").toUpperCase();
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < normalized.length(); i++) {
            if (i > 0 && i % 4 == 0) {
                sb.append("-");
            }
            sb.append(normalized.charAt(i));
        }
        return sb.toString();
    }
}

package com.example.mfa.security;

import com.example.mfa.domain.AppUser;
import com.example.mfa.repository.UserRepository;
import java.util.ArrayList;
import java.util.Iterator;
import java.util.List;
import java.util.Optional;
import java.util.UUID;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class MfaService {
    private final UserRepository userRepository;
    private final BackupCodeService backupCodeService;

    public MfaService(UserRepository userRepository, BackupCodeService backupCodeService) {
        this.userRepository = userRepository;
        this.backupCodeService = backupCodeService;
    }

    @Transactional
    public List<String> enableMfa(Long userId) {
        AppUser user = userRepository.findById(userId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        user.setMfaEnabled(true);
        user.setMfaSecret(UUID.randomUUID().toString().replace("-", ""));
        List<String> plainCodes = backupCodeService.generatePlainBackupCodes(10);
        user.setBackupCodeHashes(backupCodeService.hashBackupCodes(plainCodes));
        userRepository.save(user);
        return plainCodes;
    }

    @Transactional
    public void disableMfa(Long userId) {
        AppUser user = userRepository.findById(userId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        user.setMfaEnabled(false);
        user.setMfaSecret(null);
        user.setBackupCodeHashes(new ArrayList<>());
        userRepository.save(user);
    }

    @Transactional
    public boolean authenticateWithBackupCode(String username, String rawBackupCode) {
        Optional<AppUser> optionalUser = userRepository.findByUsername(username);
        if (optionalUser.isEmpty()) {
            return false;
        }
        AppUser user = optionalUser.get();
        List<String> hashes = new ArrayList<>(user.getBackupCodeHashes());
        for (Iterator<String> it = hashes.iterator(); it.hasNext(); ) {
            String hash = it.next();
            if (backupCodeService.matches(rawBackupCode, hash)) {
                it.remove();
                user.setBackupCodeHashes(hashes);
                userRepository.save(user);
                return true;
            }
        }
        return false;
    }
}

package com.example.mfa.web;

import com.example.mfa.domain.AppUser;
import com.example.mfa.repository.UserRepository;
import com.example.mfa.security.MfaService;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.Size;
import java.util.List;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.transaction.annotation.Transactional;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/auth")
public class AuthController {
    private final UserRepository userRepository;
    private final BCryptPasswordEncoder passwordEncoder = new BCryptPasswordEncoder();
    private final MfaService mfaService;

    public AuthController(UserRepository userRepository, MfaService mfaService) {
        this.userRepository = userRepository;
        this.mfaService = mfaService;
    }

    @PostMapping("/register")
    public ResponseEntity<?> register(@RequestBody RegisterRequest request) {
        if (userRepository.existsByUsername(request.username())) {
            return ResponseEntity.status(HttpStatus.CONFLICT).body("Username already exists");
        }
        AppUser user = new AppUser(request.username(), passwordEncoder.encode(request.password()));
        userRepository.save(user);
        return ResponseEntity.status(HttpStatus.CREATED).body("User created");
    }

    @PostMapping("/login")
    public ResponseEntity<?> login(@RequestBody LoginRequest request) {
        AppUser user = userRepository.findByUsername(request.username())
                .orElse(null);
        if (user == null || !passwordEncoder.matches(request.password(), user.getPasswordHash())) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body("Invalid credentials");
        }
        if (!user.isMfaEnabled()) {
            return ResponseEntity.ok("Login successful without MFA");
        }
        return ResponseEntity.status(HttpStatus.ACCEPTED).body("MFA required");
    }

    @PostMapping("/login/backup-code")
    public ResponseEntity<?> loginWithBackupCode(@RequestBody BackupCodeLoginRequest request) {
        boolean success = mfaService.authenticateWithBackupCode(request.username(), request.backupCode());
        if (!success) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body("Invalid backup code");
        }
        return ResponseEntity.ok("Login successful using backup code");
    }

    @PostMapping("/mfa/enable/{userId}")
    public ResponseEntity<?> enableMfa(@PathVariable Long userId) {
        List<String> codes = mfaService.enableMfa(userId);
        return ResponseEntity.ok(new BackupCodesResponse(codes));
    }

    @PostMapping("/mfa/disable/{userId}")
    public ResponseEntity<?> disableMfa(@PathVariable Long userId) {
        mfaService.disableMfa(userId);
        return ResponseEntity.ok("MFA disabled");
    }

    public record RegisterRequest(@NotBlank String username, @NotBlank @Size(min = 8) String password) {
    }

    public record LoginRequest(@NotBlank String username, @NotBlank String password) {
    }

    public record BackupCodeLoginRequest(@NotBlank String username, @NotBlank String backupCode) {
    }

    public record BackupCodesResponse(List<String> backupCodes) {
    }
}

